obj.a = 2; // \u4E25\u683C\u6A21\u5F0F\u4E0B\u62A5\u9519\uFF0C\u975E\u4E25\u683C\u6A21\u5F0F\u4E0B\u9759\u9ED8\u5931\u8D25
console.log(obj); // {a: 1}

