const constantize = (obj) => {
  Object.freeze(obj);
  Object.keys(obj).forEach((key) => {
    if (typeof obj[key] === 'object' && obj[key] !== null) {
      constantize(obj[key]);
    }
  });
};

const deepObj = Object.freeze({
  a: 1,
  b: { c: 2 },
});
deepObj.b.c = 3; // \u6D45\u51BB\u7ED3\uFF0C\u5185\u5C42\u5BF9\u8C61\u53EF\u4EE5\u4FEE\u6539
console.log(deepObj); // {a: 1, b: {c: 3}}

constantize(deepObj);
deepObj.b.c = 4; // \u6DF1\u51BB\u7ED3\uFF0C\u5185\u5C42\u5BF9\u8C61\u4E0D\u53EF\u4FEE\u6539
console.log(deepObj); // {a: 1, b: {c: 3}}
